class PaymentModule {
  final PaymentConfig config;
  final BackendClient backend;
  final InAppPurchase _iap = InAppPurchase.instance;

  final StreamController<PaymentEvent> _events = StreamController.broadcast();
  Stream<PaymentEvent> get events => _events.stream;

  StreamSubscription<List<PurchaseDetails>>? _purchaseSub;
  bool _initialized = false;

  final Map<String, ProductDetails> _products = {};
  Map<String, ProductDetails> get products => Map.unmodifiable(_products);

  final Map<String, String> _checkoutSessionByPurchaseId = {};
  final Set<String> _verifyingPurchaseIds = {};

  PaymentModule({required this.config, required this.backend});

  void _emit(PaymentEventType type, String message, {Json? data}) {
    if (config.enableVerboseLogs) {
      // ignore: avoid_print
      print('[PaymentModule] $type: $message ${data ?? {}}');
    }
    _events.add(PaymentEvent(type, message, data: data));
  }

  Future<void> init({bool fetchProducts = true}) async {
    if (_initialized) return;

    _emit(PaymentEventType.info, 'Initializing payment module');
    final available = await _iap.isAvailable();
    if (!available) {
      _emit(PaymentEventType.warning, 'In-app purchases not available on this device');
    }

    if (Platform.isIOS) {
      final skAddition = _iap.getPlatformAddition<InAppPurchaseStoreKitPlatformAddition>();
      await skAddition.setDelegate(_StoreKitDelegate(config.enableVerboseLogs, _emit));
    }

    _purchaseSub = _iap.purchaseStream.listen(
      _onPurchaseUpdate,
      onError: (e, st) => _emit(PaymentEventType.error, 'Purchase stream error', data: {'error': '$e'}),
      cancelOnError: false,
    );

    _initialized = true;

    if (fetchProducts) {
      await refreshProducts();
    }
  }

  Future<void> dispose() async {
    if (Platform.isIOS) {
      try {
        final skAddition = _iap.getPlatformAddition<InAppPurchaseStoreKitPlatformAddition>();
        await skAddition.setDelegate(null);
      } catch (_) {}
    }
    await _purchaseSub?.cancel();
    _purchaseSub = null;
    await _events.close();
    _initialized = false;
  }

  Future<void> refreshProducts() async {
    if (!_initialized) await init(fetchProducts: false);
    if (config.iapProductIds.isEmpty) return;

    final resp = await _iap.queryProductDetails(config.iapProductIds);
    if (resp.error != null) {
      throw PaymentException('iap_query_failed', resp.error!.message);
    }
    for (final p in resp.productDetails) {
      _products[p.id] = p;
    }
    if (resp.notFoundIDs.isNotEmpty) {
      _emit(PaymentEventType.warning, 'Some product IDs not found', data: {'notFoundIDs': resp.notFoundIDs});
    }
    _emit(PaymentEventType.info, 'Products refreshed', data: {'count': _products.length});
  }

  Future<void> restorePurchases() async {
    if (!_initialized) await init(fetchProducts: false);
    _emit(PaymentEventType.info, 'Restoring purchases');
    await _iap.restorePurchases();
  }

  Future<void> buyConsumable({
    required String productId,
    String? currencyCode,
    String? locale,
  }) async {
    await _buy(productId: productId, consumable: true, currencyCode: currencyCode, locale: locale);
  }

  Future<void> buyNonConsumable({
    required String productId,
    String? currencyCode,
    String? locale,
  }) async {
    await _buy(productId: productId, consumable: false, currencyCode: currencyCode, locale: locale);
  }

  Future<void> _buy({
    required String productId,
    required bool consumable,
    String? currencyCode,
    String? locale,
  }) async {
    if (!_initialized) await init(fetchProducts: false);
    final details = _products[productId];
    if (details == null) {
      await refreshProducts();
    }
    final d = _products[productId];
    if (d == null) {
      throw PaymentException('product_not_loaded', 'Product details not loaded for $productId');
    }

    final deviceIdHash = await DeviceId.getStableIdHash();
    final store = Platform.isIOS ? 'app_store' : (Platform.isAndroid ? 'play_store' : 'unknown');

    final session = await backend.createIapCheckoutSession(
      productId: productId,
      store: store,
      currencyCode: currencyCode ?? d.currencyCode,
      locale: locale ?? Platform.localeName,
      deviceIdHash: deviceIdHash,
    );

    final checkoutSessionId = (session['checkoutSessionId'] ?? '').toString();
    if (checkoutSessionId.isEmpty) {
      throw PaymentException('no_checkout_session', 'Backend did not return checkoutSessionId');
    }

    final purchaseParam = PurchaseParam(productDetails: d, applicationUserName: config.applicationUserId);

    _emit(PaymentEventType.purchasePending, 'Starting purchase flow', data: {
      'productId': productId,
      'consumable': consumable,
      'checkoutSessionId': checkoutSessionId,
    });

    bool started = false;
    if (consumable) {
      started = await _iap.buyConsumable(
        purchaseParam: purchaseParam,
        autoConsume: Platform.isAndroid ? config.iapAutoConsumeAndroid : true,
      );
    } else {
      started = await _iap.buyNonConsumable(purchaseParam: purchaseParam);
    }

    if (!started) {
      throw PaymentException('iap_not_started', 'Purchase flow did not start');
    }
  }

  Future<Json> payWithWallet({
    required MobileWalletType walletType,
    required String merchantName,
    required String merchantAccountId,
    required int amountMinor,
    required String currencyCode,
    required String countryCode,
    String? orderId,
    Json? metadata,
  }) async {
    if (!_initialized) await init(fetchProducts: false);

    if (config.isProd && config.allowTestCardsOrTokensInProd == false) {
      // Token content cannot be validated safely here; this flag exists to prevent accidental enabling
      // of test modes on server. Enforce on server as well.
    }

    final deviceIdHash = await DeviceId.getStableIdHash();

    final ready = await WalletBridge.isReady(walletType);
    if (!ready) {
      throw PaymentException('wallet_not_ready', '${walletType.name} is not available or not configured');
    }

    _emit(PaymentEventType.walletPaymentPending, 'Creating wallet intent', data: {
      'walletType': walletType.name,
      'amountMinor': amountMinor,
      'currencyCode': currencyCode,
      'countryCode': countryCode,
    });

    final intent = await backend.createWalletPaymentIntent(
      walletType: walletType,
      amountMinor: amountMinor,
      currencyCode: currencyCode,
      countryCode: countryCode,
      merchantAccountId: merchantAccountId,
      deviceIdHash: deviceIdHash,
      orderId: orderId,
      metadata: metadata,
    );

    final intentId = (intent['intentId'] ?? '').toString();
    final clientSecret = (intent['clientSecret'] ?? '').toString();

    if (intentId.isEmpty || clientSecret.isEmpty) {
      throw PaymentException('wallet_intent_invalid', 'Backend did not return intentId/clientSecret');
    }

    String token;
    try {
      token = await WalletBridge.requestPaymentToken(
        type: walletType,
        merchantName: merchantName,
        countryCode: countryCode,
        currencyCode: currencyCode,
        amountMinor: amountMinor,
        intentClientSecret: clientSecret,
        metadata: metadata,
      );
    } on Object catch (e, st) {
      _emit(PaymentEventType.walletPaymentFailed, 'Wallet tokenization failed', data: {'error': '$e'});
      throw PaymentException('wallet_tokenization_failed', 'Wallet tokenization failed', cause: e, stackTrace: st);
    }

    _emit(PaymentEventType.gatewayChargePending, 'Confirming wallet payment on backend', data: {
      'intentId': intentId,
      'walletType': walletType.name,
    });

    try {
      final confirmed = await backend.confirmWalletPayment(
        intentId: intentId,
        walletType: walletType,
        token: token,
        deviceIdHash: deviceIdHash,
      );
      _emit(PaymentEventType.walletPaymentSucceeded, 'Wallet payment confirmed', data: {
        'intentId': intentId,
        'status': confirmed['status'],
      });
      _emit(PaymentEventType.gatewayChargeSucceeded, 'Gateway charge succeeded', data: {
        'intentId': intentId,
        'status': confirmed['status'],
      });
      return confirmed;
    } on Object catch (e, st) {
      _emit(PaymentEventType.gatewayChargeFailed, 'Gateway charge failed', data: {'intentId': intentId, 'error': '$e'});
      throw PaymentException('wallet_confirm_failed', 'Wallet payment confirmation failed', cause: e, stackTrace: st);
    }
  }

  Future<void> _onPurchaseUpdate(List<PurchaseDetails> purchases) async {
    for (final p in purchases) {
      try {
        if (p.status == PurchaseStatus.pending) {
          _emit(PaymentEventType.purchasePending, 'Purchase pending', data: _purchaseData(p));
          continue;
        }

        if (p.status == PurchaseStatus.error) {
          _emit(PaymentEventType.purchaseFailed, 'Purchase error', data: {
            ..._purchaseData(p),
            'error': p.error?.message,
            'errorCode': p.error?.code,
            'errorDetails': p.error?.details,
          });
          await _completeIfNeeded(p);
          continue;
        }

        if (p.status == PurchaseStatus.canceled) {
          _emit(PaymentEventType.purchaseFailed, 'Purchase canceled', data: _purchaseData(p));
          await _completeIfNeeded(p);
          continue;
        }

        if (p.status == PurchaseStatus.purchased || p.status == PurchaseStatus.restored) {
          final store = Platform.isIOS ? 'app_store' : (Platform.isAndroid ? 'play_store' : 'unknown');

          final purchaseId = p.purchaseID ?? p.verificationData.serverVerificationData.hashCode.toString();
          if (_verifyingPurchaseIds.contains(purchaseId)) {
            continue;
          }
          _verifyingPurchaseIds.add(purchaseId);

          final deviceIdHash = await DeviceId.getStableIdHash();
          final checkoutSessionId = _checkoutSessionByPurchaseId[purchaseId] ?? '';

          _emit(
            p.status == PurchaseStatus.restored ? PaymentEventType.purchaseRestored : PaymentEventType.purchasePending,
            'Verifying purchase with backend',
            data: {..._purchaseData(p), 'store': store, 'checkoutSessionId': checkoutSessionId},
          );

          final result = await backend.verifyIapReceipt(
            store: store,
            productId: p.productID,
            purchaseId: purchaseId,
            verificationData: p.verificationData.serverVerificationData,
            verificationSource: p.verificationData.source,
            transactionDate: p.transactionDate ?? '',
            deviceIdHash: deviceIdHash,
            checkoutSessionId: checkoutSessionId,
          );

          final status = (result['status'] ?? '').toString();
          final ok = status == 'ok' || status == 'granted' || status == 'success';

          if (ok) {
            _emit(PaymentEventType.purchaseSucceeded, 'Purchase verified and granted', data: {
              ..._purchaseData(p),
              'backendStatus': status,
              'entitlements': result['entitlements'],
            });
          } else {
            _emit(PaymentEventType.purchaseFailed, 'Purchase verification failed', data: {
              ..._purchaseData(p),
              'backendStatus': status,
              'result': result,
            });
          }

          await _completeIfNeeded(p);

          if (Platform.isAndroid && config.iapAutoConsumeAndroid == false) {
            final isConsumable = (result['consumable'] == true);
            if (isConsumable) {
              await _consumeAndroidIfNeeded(p);
            }
          }

          _verifyingPurchaseIds.remove(purchaseId);
        }
      } on Object catch (e, st) {
        _emit(PaymentEventType.error, 'Unhandled purchase processing error', data: {
          ..._purchaseData(p),
          'error': '$e',
        });
        try {
          await _completeIfNeeded(p);
        } catch (_) {}
        _verifyingPurchaseIds.remove(p.purchaseID ?? '');
        if (config.enableVerboseLogs) {
          // ignore: avoid_print
          print(st);
        }
      }
    }
  }

  Future<void> _completeIfNeeded(PurchaseDetails p) async {
    if (p.pendingCompletePurchase) {
      await _iap.completePurchase(p);
    }
  }

  Future<void> _consumeAndroidIfNeeded(PurchaseDetails p) async {
    if (!Platform.isAndroid) return;
    if (p is! GooglePlayPurchaseDetails) return;

    final addition = _iap.getPlatformAddition<InAppPurchaseAndroidPlatformAddition>();
    try {
      await addition.consumePurchase(p);
      _emit(PaymentEventType.info, 'Consumed Android purchase', data: _purchaseData(p));
    } on Object catch (e) {
      _emit(PaymentEventType.warning, 'Failed to consume Android purchase', data: {..._purchaseData(p), 'error': '$e'});
    }
  }

  Json _purchaseData(PurchaseDetails p) => <String, dynamic>{
        'productId': p.productID,
        'purchaseId': p.purchaseID,
        'status': p.status.name,
        'pendingCompletePurchase': p.pendingCompletePurchase,
        'transactionDate': p.transactionDate,
        'verificationSource': p.verificationData.source,
      };
}

class _StoreKitDelegate implements SKPaymentQueueDelegateWrapper {
  final bool verbose;
  final void Function(PaymentEventType, String, {Json? data}) emit;

  _StoreKitDelegate(this.verbose, this.emit);

  @override
  bool shouldContinueTransaction(SKPaymentTransactionWrapper transaction, SKStorefrontWrapper storefront) {
    return true;
  }

  @override
  bool shouldShowPriceConsent() {
    return false;
  }
}

class PaymentsWalletPluginScaffold {
  static const String kotlinAndroid = r'''
package com.example.payments

import android.app.Activity
import android.content.Context
import android.provider.Settings
import androidx.annotation.NonNull
import io.flutter.embedding.engine.plugins.FlutterPlugin
import io.flutter.embedding.engine.plugins.activity.ActivityAware
import io.flutter.embedding.engine.plugins.activity.ActivityPluginBinding
import io.flutter.plugin.common.MethodCall
import io.flutter.plugin.common.MethodChannel
import org.json.JSONObject

class PaymentsWalletPlugin: FlutterPlugin, MethodChannel.MethodCallHandler, ActivityAware {
  private lateinit var walletChannel: MethodChannel
  private lateinit var deviceIdChannel: MethodChannel
  private var activity: Activity? = null
  private var context: Context? = null

  override fun onAttachedToEngine(@NonNull binding: FlutterPlugin.FlutterPluginBinding) {
    context = binding.applicationContext
    walletChannel = MethodChannel(binding.binaryMessenger, "payments.wallet")
    deviceIdChannel = MethodChannel(binding.binaryMessenger, "payments.device_id")
    walletChannel.setMethodCallHandler(this)
    deviceIdChannel.setMethodCallHandler(this)
  }

  override fun onDetachedFromEngine(@NonNull binding: FlutterPlugin.FlutterPluginBinding) {
    walletChannel.setMethodCallHandler(null)
    deviceIdChannel.setMethodCallHandler(null)
    context = null
  }

  override fun onAttachedToActivity(binding: ActivityPluginBinding) {
    activity = binding.activity
  }

  override fun onDetachedFromActivityForConfigChanges() {
    activity = null
  }

  override fun onReattachedToActivityForConfigChanges(binding: ActivityPluginBinding) {
    activity = binding.activity
  }

  override fun onDetachedFromActivity() {
    activity = null
  }

  override fun onMethodCall(@NonNull call: MethodCall, @NonNull result: MethodChannel.Result) {
    when (call.method) {
      "getStableId" -> {
        val ctx = context
        if (ctx == null) { result.success(null); return }
        val id = Settings.Secure.getString(ctx.contentResolver, Settings.Secure.ANDROID_ID)
        result.success(id)
      }
      "isReady" -> {
        // TODO: Implement Google Pay readiness check via PaymentsClient.isReadyToPay.
        result.success(true)
      }
      "requestPaymentToken" -> {
        // TODO: Implement Google Pay tokenization flow using PaymentsClient.loadPaymentData.
        // Return paymentMethodData.tokenizationData.token as String.
        result.error("not_implemented", "Google Pay tokenization not implemented in scaffold", null)
      }
      else -> result.notImplemented()
    }
  }
}
''';

