class PaymentsQuickStart {
  static PaymentModule create({
    required PaymentEnvironment environment,
    required Uri backendBaseUrl,
    required String backendPublicKeyId,
    required String applicationUserId,
    required Set<String> iapProductIds,
    String? bearerToken,
    DateTime? bearerTokenExpUtc,
    bool enableVerboseLogs = false,
  }) {
    final cfg = PaymentConfig(
      environment: environment,
      backendBaseUrl: backendBaseUrl,
      backendPublicKeyId: backendPublicKeyId,
      applicationUserId: applicationUserId,
      iapProductIds: iapProductIds,
      enableVerboseLogs: enableVerboseLogs,
    );
    final backend = BackendClient(cfg);
    final module = PaymentModule(config: cfg, backend: backend);
    if (bearerToken != null) {
      backend.setAuthToken(bearerToken, expiresAtUtc: bearerTokenExpUtc);
    }
    return module;
  }
}